from flask import Flask, request, jsonify
import os
import redis

app = Flask(__name__)

redis_client = redis.Redis(
    host=os.getenv("REDIS_HOST", "localhost"),
    port=int(os.getenv("REDIS_PORT", "6379")),
    db=int(os.getenv("REDIS_DB", "0")),
    password=os.getenv("REDIS_PASSWORD"),
    decode_responses=True,
)

ALLOWED_COMMANDS = {
    "PING": {"min_args": 0, "max_args": 1},
    "GET": {"min_args": 1, "max_args": 1},
    "MGET": {"min_args": 1, "max_args": None},
    "SET": {"min_args": 2, "max_args": None},
    "DEL": {"min_args": 1, "max_args": None},
    "EXISTS": {"min_args": 1, "max_args": None},
    "EXPIRE": {"min_args": 2, "max_args": 2},
    "TTL": {"min_args": 1, "max_args": 1},
    "INCR": {"min_args": 1, "max_args": 1},
    "DECR": {"min_args": 1, "max_args": 1},
    "HGET": {"min_args": 2, "max_args": 2},
    "HSET": {"min_args": 3, "max_args": None},
    "HGETALL": {"min_args": 1, "max_args": 1},
    "LPUSH": {"min_args": 2, "max_args": None},
    "RPUSH": {"min_args": 2, "max_args": None},
    "LRANGE": {"min_args": 3, "max_args": 3},
    "SADD": {"min_args": 2, "max_args": None},
    "SMEMBERS": {"min_args": 1, "max_args": 1},
    "ZADD": {"min_args": 3, "max_args": None},
    "ZRANGE": {"min_args": 3, "max_args": 5},
}

def parse_command(command_str):
    parts = command_str.strip().split()
    if not parts:
        raise ValueError("Empty command")
    cmd = parts[0].upper()
    args = parts[1:]
    if cmd not in ALLOWED_COMMANDS:
        raise ValueError(f"Command '{cmd}' is not allowed")
    rules = ALLOWED_COMMANDS[cmd]
    if len(args) < rules["min_args"]:
        raise ValueError(f"Command '{cmd}' requires at least {rules['min_args']} argument(s)")
    if rules["max_args"] is not None and len(args) > rules["max_args"]:
        raise ValueError(f"Command '{cmd}' allows at most {rules['max_args']} argument(s)")
    return cmd, args

@app.route("/admin/redis", methods=["GET", "POST"])
def admin_redis():
    command_str = request.args.get("command") or request.form.get("command")
    if not command_str:
        return jsonify({"error": "Missing 'command' parameter"}), 400

    try:
        cmd, args = parse_command(command_str)
        result = redis_client.execute_command(cmd, *args)
        return jsonify({
            "ok": True,
            "command": cmd,
            "args": args,
            "result": result,
        })
    except ValueError as e:
        return jsonify({"ok": False, "error": str(e)}), 400
    except redis.RedisError as e:
        return jsonify({"ok": False, "error": "Redis error", "details": str(e)}), 502
    except Exception as e:
        return jsonify({"ok": False, "error": "Internal server error", "details": str(e)}), 500

@app.route("/health", methods=["GET"])
def health():
    try:
        pong = redis_client.ping()
        return jsonify({"ok": True, "redis": pong})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))